<!DOCTYPE html>
<html>
<head>
<title>WastedToken Mint</title>
<style>
body {
  font-family: sans-serif;
  margin: 0;
  overflow: hidden;
}

#hero-container {
  width: 100vw;
  height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  background-color: #222;
}

#coin-hero {
  width: 200px;
  height: 200px;
}

.edition {
  display: flex;
  flex-direction: column;
  align-items: center;
  margin: 20px;
}

.edition-canvas {
  width: 150px;
  height: 150px;
}

.buy {
  background-color: #ff6b6b;
  color: white;
  border: none;
  padding: 10px 20px;
  cursor: pointer;
  font-size: 16px;
  transition: background-color 0.3s ease;
}

.buy:hover {
  background-color: #e64a4a;
}

#about-section {
  width: 80%;
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;
  background-color: #333;
  border-radius: 10px;
}

#about-section h2 {
  color: #eee;
  margin-bottom: 15px;
}
</style>
</head>
<body>

<div id="hero-container">
  <canvas id="coin-hero"></canvas>
</div>

<div id="about-section">
  <h2>About WastedToken Mint</h2>
  <p>WastedToken Mint specializes in crafting high-quality, collectible challenge coins. Each coin is meticulously designed and hand-minted to ensure lasting value and prestige. We pride ourselves on our attention to detail and commitment to creating truly unique pieces for collectors and enthusiasts.</p>
</div>

<div id="edition-grid">
  <div class="edition" data-edition="bronze" data-state="available">
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>
  <div class="edition" data-edition="silver" data-state="available">
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>
  <div class="edition" data-edition="gold" data-state="sold-out">
    <canvas class="edition-canvas"></canvas>
    <button class="buy" disabled>SOLD OUT</button>
  </div>
  <div class="edition" data-edition="black" data-state="coming-soon">
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>
</div>

<script>
const canvas = document.getElementById('coin-hero');
const ctx = canvas.getContext('2d');
ctx.fillStyle = '#333';
ctx.fillRect(0, 0, canvas.width, canvas.height);

let angle = 0;
const rotationSpeed = 0.02;

function setTime(t) {
  angle += t * rotationSpeed;
  render();
}

function render() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  // Coin parameters
  const coinRadius = 80;
  const emblemOffset = 20;
  const denominationOffset = 50;
  const reedWidth = 3;
  const specularStrength = 0.7;

  // Front face
  ctx.save();
  ctx.translate(coinRadius, canvas.height / 2);
  ctx.rotate(angle);

  // Emblem
  ctx.fillStyle = '#007bff'; // WastedToken Mint color
  ctx.beginPath();
  ctx.arc(0, -emblemOffset, 30, 0, Math.PI * 2);
  ctx.fill();

  // Denomination
  ctx.fillStyle = '#ffffff';
  ctx.font = '16px Arial';
  ctx.textAlign = 'center';
  ctx.fillText('10,000 TOKENS', 0, -denominationOffset);


  // Reeded edge
  ctx.beginPath();
  ctx.rect(-coinRadius + reedWidth, -coinRadius, 2 * coinRadius, coinRadius);
  ctx.stroke();

  ctx.restore();

  // Back face (flip)
  ctx.save();
  ctx.translate(coinRadius, canvas.height / 2);
  ctx.rotate(-angle);

  // Emblem (flipped)
  ctx.fillStyle = '#007bff'; // WastedToken Mint color
  ctx.beginPath();
  ctx.arc(0, -emblemOffset, 30, 0, Math.PI * 2);
  ctx.fill();

  // Denomination (flipped)
  ctx.fillStyle = '#ffffff';
  ctx.font = '16px Arial';
  ctx.textAlign = 'center';
  ctx.fillText('10,000 TOKENS', 0, -denominationOffset);


  // Reeded edge (flipped)
  ctx.beginPath();
  ctx.rect(-coinRadius + reedWidth, -coinRadius, 2 * coinRadius, coinRadius);
  ctx.stroke();

  ctx.restore();

  // Specular highlight
  ctx.fillStyle = 'gold';
  ctx.beginPath();
  ctx.arc(0, canvas.height / 2, 30, 0, Math.PI * 2);
  ctx.fill();
}


function pause() {
  window.requestAnimationFrame(pause);
}

// Initial render
render();

// Start animation loop
window.demo = {
  canvas,
  setTime: setTime,
  pause: pause
};
</script>

</body>
</html>
